+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { EventBus } from '../../src/events/event-bus.js';
+import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
+import { NotificationHistoryService, resetNotificationLogIdCounter } from '../../src/services/notification-history.service.js';
+import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
+import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
+import { UserPreferencesRepository } from '../../src/repositories/user-preferences.repository.js';
+import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
+import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
+import { WebhookAdapter, InMemoryWebhookTransport } from '../../src/adapters/webhook.adapter.js';
+import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
+
+// --- Full pipeline harness ---
+
+interface Pipeline {
+  db: Database;
+  eventBus: EventBus;
+  notificationService: NotificationService;
+  historyService: NotificationHistoryService;
+  preferencesService: PreferencesService;
+  emailTransport: InMemoryTransport;
+  smsTransport: InMemorySmsTransport;
+  webhookTransport: InMemoryWebhookTransport;
+  emailAdapter: EmailAdapter;
+  smsAdapter: SmsAdapter;
+  webhookAdapter: WebhookAdapter;
+}
+
+function buildPipeline(): Pipeline {
+  const db = new Database();
+  const eventBus = new EventBus();
+
+  // Repositories
+  const logRepo = new NotificationLogRepository(db);
+  const prefsRepo = new UserPreferencesRepository(db);
+
+  // Services
+  const historyService = new NotificationHistoryService(logRepo);
+  const preferencesService = new PreferencesService(prefsRepo);
+
+  // Adapters with in-memory transports
+  const emailTransport = new InMemoryTransport();
+  const emailAdapter = new EmailAdapter(
+    { fromAddress: 'noreply@taskflow.io', fromName: 'TaskFlow Pro' },
+    emailTransport,
+  );
+
+  const smsTransport = new InMemorySmsTransport();
+  const smsAdapter = new SmsAdapter(
+    { fromNumber: '+15551234567' },
+    smsTransport,
+  );
+
+  const webhookTransport = new InMemoryWebhookTransport();
+  const webhookAdapter = new WebhookAdapter(
+    { defaultUrl: 'https://hooks.example.com/notify' },
+    webhookTransport,
+  );
+
+  // Wire everything together
+  const notificationService = new NotificationService(eventBus);
+  notificationService.registerAdapter(emailAdapter);
+  notificationService.registerAdapter(smsAdapter);
+  notificationService.registerAdapter(webhookAdapter);
+  notificationService.setPreferencesService(preferencesService);
+  notificationService.setHistoryService(historyService);
+
+  return {
+    db,
+    eventBus,
+    notificationService,
+    historyService,
+    preferencesService,
+    emailTransport,
+    smsTransport,
+    webhookTransport,
+    emailAdapter,
+    smsAdapter,
+    webhookAdapter,
+  };
+}
+
+describe('Notification Pipeline Integration', () => {
+  let p: Pipeline;
+
+  beforeEach(() => {
+    resetNotificationIdCounter();
+    resetNotificationLogIdCounter();
+    resetPreferencesIdCounter();
+    p = buildPipeline();
+  });
+
+  // ---------------------------------------------------------------
+  // 1. Email channel — end-to-end
+  // ---------------------------------------------------------------
+  describe('email channel', () => {
+    it('should deliver email notification and log to history', async () => {
+      const result = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Order #100',
+        body: 'Your order has been placed.',
+        userId: 'user-1',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.channel).toBe('email');
+
+      // Transport received the email
+      const sent = p.emailTransport.getSentEmails();
+      expect(sent).toHaveLength(1);
+      expect(sent[0].to).toBe('alice@example.com');
+      expect(sent[0].subject).toBe('Order #100');
+      expect(sent[0].html).toContain('Order Confirmation');
+
+      // History recorded the delivery
+      const logs = p.historyService.getByChannel('email');
+      expect(logs).toHaveLength(1);
+      expect(logs[0].status).toBe('delivered');
+      expect(logs[0].recipient).toBe('alice@example.com');
+      expect(logs[0].userId).toBe('user-1');
+    });
+
+    it('should deliver email when user has email preferences enabled', async () => {
+      // Explicitly create preferences with email enabled
+      p.preferencesService.getOrCreatePreferences('user-1');
+
+      const result = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Order #200',
+        body: 'Items shipped.',
+        userId: 'user-1',
+      });
+
+      expect(result.success).toBe(true);
+      expect(p.emailTransport.getSentEmails()).toHaveLength(1);
+    });
+  });
+
+  // ---------------------------------------------------------------
+  // 2. SMS channel — end-to-end
+  // ---------------------------------------------------------------
+  describe('sms channel', () => {
+    it('should deliver SMS notification and log to history', async () => {
+      const result = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'sms',
+        recipient: '+15559876543',
+        subject: 'Order #300',
+        body: 'Your order is confirmed.',
+        userId: 'user-2',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.channel).toBe('sms');
+
+      // Transport received the SMS
+      const sent = p.smsTransport.getSentMessages();
+      expect(sent).toHaveLength(1);
+      expect(sent[0].to).toBe('+15559876543');
+      expect(sent[0].body).toContain('Order Confirmed');
+
+      // History recorded
+      const logs = p.historyService.getByChannel('sms');
+      expect(logs).toHaveLength(1);
+      expect(logs[0].status).toBe('delivered');
+      expect(logs[0].userId).toBe('user-2');
+    });
+
+    it('should deliver SMS when user has SMS preferences enabled', async () => {
+      p.preferencesService.getOrCreatePreferences('user-2');
+
+      const result = await p.notificationService.dispatchNotification({
+        type: 'user-welcome',
+        channel: 'sms',
+        recipient: '+15559876543',
+        subject: 'Welcome!',
+        body: 'Welcome to TaskFlow.',
+        userId: 'user-2',
+      });
+
+      expect(result.success).toBe(true);
+      expect(p.smsTransport.getSentMessages()).toHaveLength(1);
+    });
+  });
+
+  // ---------------------------------------------------------------
+  // 3. Webhook channel — end-to-end
+  // ---------------------------------------------------------------
+  describe('webhook channel', () => {
+    it('should deliver webhook notification and log to history', async () => {
+      const result = await p.notificationService.dispatchNotification({
+        type: 'system-alert',
+        channel: 'webhook',
+        recipient: 'https://hooks.example.com/alerts',
+        subject: 'CPU Spike',
+        body: 'CPU usage exceeded 90%.',
+        priority: 'high',
+        userId: 'user-3',
+      });
+
+      expect(result.success).toBe(true);
+      expect(result.channel).toBe('webhook');
+
+      // Transport received the webhook POST
+      const posted = p.webhookTransport.getPostedWebhooks();
+      expect(posted).toHaveLength(1);
+      expect(posted[0].url).toBe('https://hooks.example.com/alerts');
+      expect(posted[0].body.subject).toBe('CPU Spike');
+      expect(posted[0].body.priority).toBe('high');
+
+      // History recorded
+      const logs = p.historyService.getByChannel('webhook');
+      expect(logs).toHaveLength(1);
+      expect(logs[0].status).toBe('delivered');
+    });
+
+    it('should use default URL when recipient is not a URL', async () => {
+      const result = await p.notificationService.dispatchNotification({
+        type: 'system-alert',
+        channel: 'webhook',
+        recipient: 'ops-team',
+        subject: 'Disk Full',
+        body: 'Disk usage exceeded 95%.',
+      });
+
+      expect(result.success).toBe(true);
+      const posted = p.webhookTransport.getPostedWebhooks();
+      expect(posted[0].url).toBe('https://hooks.example.com/notify');
+    });
+  });
+
+  // ---------------------------------------------------------------
+  // 4. User preferences — suppression
+  // ---------------------------------------------------------------
+  describe('preference suppression', () => {
+    it('should suppress email when user disables email channel', async () => {
+      p.preferencesService.updateEmailPreferences('user-1', { enabled: false });
+
+      const result = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Order #400',
+        body: 'Suppressed.',
+        userId: 'user-1',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Notification suppressed by user preferences');
+      expect(p.emailTransport.getSentEmails()).toHaveLength(0);
+
+      // History records suppression
+      const logs = p.historyService.getByUserId('user-1');
+      expect(logs).toHaveLength(1);
+      expect(logs[0].status).toBe('suppressed');
+    });
+
+    it('should suppress SMS when user disables SMS channel', async () => {
+      p.preferencesService.updateSmsPreferences('user-2', { enabled: false });
+
+      const result = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'sms',
+        recipient: '+15559876543',
+        subject: 'Order #500',
+        body: 'Suppressed.',
+        userId: 'user-2',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Notification suppressed by user preferences');
+      expect(p.smsTransport.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should suppress webhook when user disables webhook channel', async () => {
+      p.preferencesService.updateWebhookPreferences('user-3', { enabled: false });
+
+      const result = await p.notificationService.dispatchNotification({
+        type: 'system-alert',
+        channel: 'webhook',
+        recipient: 'https://hooks.example.com/alerts',
+        subject: 'Alert',
+        body: 'Suppressed.',
+        userId: 'user-3',
+      });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Notification suppressed by user preferences');
+      expect(p.webhookTransport.getPostedWebhooks()).toHaveLength(0);
+    });
+
+    it('should suppress email for a specific disabled category', async () => {
+      p.preferencesService.updateEmailPreferences('user-1', {
+        categories: { orders: false },
+      });
+
+      // Order notification → suppressed (orders category disabled)
+      const orderResult = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Order',
+        body: 'Order details.',
+        userId: 'user-1',
+      });
+      expect(orderResult.success).toBe(false);
+
+      // Account notification → delivered (account category still enabled)
+      const accountResult = await p.notificationService.dispatchNotification({
+        type: 'user-welcome',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Welcome',
+        body: 'Welcome!',
+        userId: 'user-1',
+      });
+      expect(accountResult.success).toBe(true);
+
+      expect(p.emailTransport.getSentEmails()).toHaveLength(1);
+    });
+
+    it('should allow notification when no preferences exist (default opt-in)', async () => {
+      const result = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'newuser@example.com',
+        subject: 'Order',
+        body: 'First order.',
+        userId: 'user-new',
+      });
+
+      expect(result.success).toBe(true);
+      expect(p.emailTransport.getSentEmails()).toHaveLength(1);
+    });
+
+    it('should allow notification when no userId is provided', async () => {
+      const result = await p.notificationService.dispatchNotification({
+        type: 'system-alert',
+        channel: 'email',
+        recipient: 'ops@example.com',
+        subject: 'System Alert',
+        body: 'Anonymous alert.',
+      });
+
+      expect(result.success).toBe(true);
+    });
+
+    it('should suppress one channel while allowing another for the same user', async () => {
+      // Disable email but keep SMS enabled
+      p.preferencesService.updateEmailPreferences('user-1', { enabled: false });
+
+      const emailResult = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Order',
+        body: 'Order placed.',
+        userId: 'user-1',
+      });
+
+      const smsResult = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'sms',
+        recipient: '+15551234567',
+        subject: 'Order',
+        body: 'Order placed.',
+        userId: 'user-1',
+      });
+
+      expect(emailResult.success).toBe(false);
+      expect(smsResult.success).toBe(true);
+
+      expect(p.emailTransport.getSentEmails()).toHaveLength(0);
+      expect(p.smsTransport.getSentMessages()).toHaveLength(1);
+
+      // History has both entries
+      const logs = p.historyService.getByUserId('user-1');
+      expect(logs).toHaveLength(2);
+      expect(logs.find(l => l.channel === 'email')!.status).toBe('suppressed');
+      expect(logs.find(l => l.channel === 'sms')!.status).toBe('delivered');
+    });
+  });
+
+  // ---------------------------------------------------------------
+  // 5. History logging
+  // ---------------------------------------------------------------
+  describe('history logging', () => {
+    it('should log all notification outcomes (delivered, failed, suppressed)', async () => {
+      // Delivered
+      await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Delivered',
+        body: 'OK',
+        userId: 'user-1',
+      });
+
+      // Failed — no adapter for in-app
+      await p.notificationService.dispatchNotification({
+        type: 'system-alert',
+        channel: 'in-app',
+        recipient: 'user-1',
+        subject: 'Failed',
+        body: 'No adapter',
+        userId: 'user-1',
+      });
+
+      // Suppressed
+      p.preferencesService.updateSmsPreferences('user-1', { enabled: false });
+      await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'sms',
+        recipient: '+15551234567',
+        subject: 'Suppressed',
+        body: 'Suppressed',
+        userId: 'user-1',
+      });
+
+      const logs = p.historyService.getByUserId('user-1');
+      expect(logs).toHaveLength(3);
+
+      const statuses = logs.map(l => l.status).sort();
+      expect(statuses).toEqual(['delivered', 'failed', 'suppressed']);
+    });
+
+    it('should support querying history by multiple filters', async () => {
+      await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Order 1',
+        body: 'First order.',
+        userId: 'user-1',
+      });
+
+      await p.notificationService.dispatchNotification({
+        type: 'user-welcome',
+        channel: 'email',
+        recipient: 'bob@example.com',
+        subject: 'Welcome Bob',
+        body: 'Welcome!',
+        userId: 'user-2',
+      });
+
+      await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'sms',
+        recipient: '+15551234567',
+        subject: 'Order SMS',
+        body: 'Order placed.',
+        userId: 'user-1',
+      });
+
+      // Query: user-1 + email
+      const user1Email = p.historyService.query({
+        userId: 'user-1',
+        channel: 'email',
+      });
+      expect(user1Email).toHaveLength(1);
+      expect(user1Email[0].type).toBe('order-confirmation');
+
+      // Query: all order-confirmation
+      const orders = p.historyService.getByType('order-confirmation');
+      expect(orders).toHaveLength(2);
+
+      // Total count
+      expect(p.historyService.count()).toBe(3);
+    });
+  });
+
+  // ---------------------------------------------------------------
+  // 6. Event-driven pipeline (EventBus → Service → Adapter → History)
+  // ---------------------------------------------------------------
+  describe('event-driven pipeline', () => {
+    it('should deliver email on user:created event and log to history', async () => {
+      const event: UserCreatedEvent = {
+        type: 'user:created',
+        user: {
+          id: 'user-10',
+          name: 'Carol',
+          email: 'carol@example.com',
+          role: 'member',
+          createdAt: new Date(),
+          updatedAt: new Date(),
+        },
+        timestamp: new Date(),
+      };
+
+      await p.eventBus.emit(event);
+
+      // Email was sent
+      const sent = p.emailTransport.getSentEmails();
+      expect(sent).toHaveLength(1);
+      expect(sent[0].to).toBe('carol@example.com');
+      expect(sent[0].subject).toContain('Welcome');
+
+      // History was recorded
+      const logs = p.historyService.getByUserId('user-10');
+      expect(logs).toHaveLength(1);
+      expect(logs[0].type).toBe('user-welcome');
+      expect(logs[0].status).toBe('delivered');
+    });
+
+    it('should deliver email on order:created event and log to history', async () => {
+      const event: OrderCreatedEvent = {
+        type: 'order:created',
+        order: {
+          id: 'order-50',
+          userId: 'user-20',
+          items: [
+            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 9.99 },
+          ],
+          total: 19.98,
+          status: 'pending',
+          createdAt: new Date(),
+          updatedAt: new Date(),
+        },
+        user: {
+          id: 'user-20',
+          name: 'Dave',
+          email: 'dave@example.com',
+          role: 'member',
+          createdAt: new Date(),
+          updatedAt: new Date(),
+        },
+        timestamp: new Date(),
+      };
+
+      await p.eventBus.emit(event);
+
+      const sent = p.emailTransport.getSentEmails();
+      expect(sent).toHaveLength(1);
+      expect(sent[0].to).toBe('dave@example.com');
+      expect(sent[0].subject).toContain('Order Confirmation');
+
+      const logs = p.historyService.getByUserId('user-20');
+      expect(logs).toHaveLength(1);
+      expect(logs[0].type).toBe('order-confirmation');
+      expect(logs[0].status).toBe('delivered');
+    });
+
+    it('should suppress event-triggered notification when preferences disable it', async () => {
+      // Disable email for user-30
+      p.preferencesService.updateEmailPreferences('user-30', { enabled: false });
+
+      const event: UserCreatedEvent = {
+        type: 'user:created',
+        user: {
+          id: 'user-30',
+          name: 'Eve',
+          email: 'eve@example.com',
+          role: 'viewer',
+          createdAt: new Date(),
+          updatedAt: new Date(),
+        },
+        timestamp: new Date(),
+      };
+
+      await p.eventBus.emit(event);
+
+      expect(p.emailTransport.getSentEmails()).toHaveLength(0);
+
+      const logs = p.historyService.getByUserId('user-30');
+      expect(logs).toHaveLength(1);
+      expect(logs[0].status).toBe('suppressed');
+    });
+  });
+
+  // ---------------------------------------------------------------
+  // 7. Notification ordering
+  // ---------------------------------------------------------------
+  describe('notification ordering', () => {
+    it('should deliver notifications to the same recipient in dispatch order', async () => {
+      const deliveryOrder: string[] = [];
+
+      // Replace email transport with one that tracks order
+      const trackingTransport: InMemoryTransport = {
+        async send(email) {
+          deliveryOrder.push(email.subject);
+          return { success: true };
+        },
+        async isConnected() {
+          return true;
+        },
+        getSentEmails: () => [],
+        clearSentEmails: () => {},
+      };
+
+      const trackingAdapter = new EmailAdapter(
+        { fromAddress: 'test@test.com', fromName: 'Test' },
+        trackingTransport,
+      );
+      p.notificationService.registerAdapter(trackingAdapter);
+
+      // Dispatch three notifications concurrently to the same recipient
+      const promises = [
+        p.notificationService.dispatchNotification({
+          type: 'order-confirmation',
+          channel: 'email',
+          recipient: 'same@example.com',
+          subject: 'First',
+          body: '1',
+        }),
+        p.notificationService.dispatchNotification({
+          type: 'order-status-update',
+          channel: 'email',
+          recipient: 'same@example.com',
+          subject: 'Second',
+          body: '2',
+        }),
+        p.notificationService.dispatchNotification({
+          type: 'user-welcome',
+          channel: 'email',
+          recipient: 'same@example.com',
+          subject: 'Third',
+          body: '3',
+        }),
+      ];
+
+      await Promise.all(promises);
+
+      expect(deliveryOrder).toEqual(['First', 'Second', 'Third']);
+    });
+
+    it('should allow concurrent delivery to different recipients', async () => {
+      const deliveryOrder: string[] = [];
+
+      const trackingTransport: InMemoryTransport = {
+        async send(email) {
+          // Simulate slow delivery for first recipient
+          if (email.to === 'slow@example.com') {
+            await new Promise(r => setTimeout(r, 30));
+          }
+          deliveryOrder.push(email.to);
+          return { success: true };
+        },
+        async isConnected() {
+          return true;
+        },
+        getSentEmails: () => [],
+        clearSentEmails: () => {},
+      };
+
+      const trackingAdapter = new EmailAdapter(
+        { fromAddress: 'test@test.com', fromName: 'Test' },
+        trackingTransport,
+      );
+      p.notificationService.registerAdapter(trackingAdapter);
+
+      const promises = [
+        p.notificationService.dispatchNotification({
+          type: 'order-confirmation',
+          channel: 'email',
+          recipient: 'slow@example.com',
+          subject: 'Slow',
+          body: 'Slow delivery.',
+        }),
+        p.notificationService.dispatchNotification({
+          type: 'order-confirmation',
+          channel: 'email',
+          recipient: 'fast@example.com',
+          subject: 'Fast',
+          body: 'Fast delivery.',
+        }),
+      ];
+
+      await Promise.all(promises);
+
+      // Fast recipient finishes before slow
+      expect(deliveryOrder[0]).toBe('fast@example.com');
+      expect(deliveryOrder[1]).toBe('slow@example.com');
+    });
+  });
+
+  // ---------------------------------------------------------------
+  // 8. Multi-channel for same user
+  // ---------------------------------------------------------------
+  describe('multi-channel delivery', () => {
+    it('should deliver same notification type across multiple channels', async () => {
+      const result1 = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'email',
+        recipient: 'alice@example.com',
+        subject: 'Order #700',
+        body: 'Your order is confirmed.',
+        userId: 'user-1',
+      });
+
+      const result2 = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'sms',
+        recipient: '+15551234567',
+        subject: 'Order #700',
+        body: 'Your order is confirmed.',
+        userId: 'user-1',
+      });
+
+      const result3 = await p.notificationService.dispatchNotification({
+        type: 'order-confirmation',
+        channel: 'webhook',
+        recipient: 'https://hooks.example.com/orders',
+        subject: 'Order #700',
+        body: 'Your order is confirmed.',
+        userId: 'user-1',
+      });
+
+      expect(result1.success).toBe(true);
+      expect(result2.success).toBe(true);
+      expect(result3.success).toBe(true);
+
+      expect(p.emailTransport.getSentEmails()).toHaveLength(1);
+      expect(p.smsTransport.getSentMessages()).toHaveLength(1);
+      expect(p.webhookTransport.getPostedWebhooks()).toHaveLength(1);
+
+      // All three logged in history
+      const logs = p.historyService.getByUserId('user-1');
